"""Interactive CLI Menu System for the Library Management System."""from datetime import datetimefrom ..services.loan_service import LoanServicefrom ..services.fine_service import FineCalculatorfrom ..models.book import Bookfrom ..models.member import Memberfrom .formatters import format_book_list, format_member_list, format_loan_listclass LibraryMenuSystem:    """Handles user interaction and command routing."""    def __init__(self, book_collection, member_collection, loan_collection):        self.books = book_collection        self.members = member_collection        self.loans = loan_collection        self.loan_service = LoanService(book_collection, member_collection, loan_collection)        self.fine_calculator = FineCalculator()    def run(self):        """Main program loop."""        self._print_header("WELCOME TO THE LIBRARY MANAGEMENT SYSTEM")        while True:            self._display_main_menu()            choice = input("\nEnter your choice: ").strip()            match choice:                case "1":                    self._book_menu()                case "2":                    self._member_menu()                case "3":                    self._loan_menu()                case "4":                    self._reports_menu()                case "5":                    if self._confirm("Are you sure you want to exit?"):                        print("\nThank you for using the Library Management System. Goodbye!")                        break                case _:                    print("\nInvalid choice. Please try again.")    # ----------------------------------------------------------------------    # Main Menu    # ----------------------------------------------------------------------    def _display_main_menu(self):        print("\n" + "=" * 40)        print("MAIN MENU")        print("=" * 40)        print("1. Book Management")        print("2. Member Management")        print("3. Loan Management")        print("4. Reports")        print("5. Exit")    # ----------------------------------------------------------------------    # Book Management    # ----------------------------------------------------------------------    def _book_menu(self):        while True:            print("\n" + "-" * 30)            print("BOOK MANAGEMENT")            print("-" * 30)            print("1. Add New Book")            print("2. Remove Book")            print("3. View All Books")            print("4. Search Books")            print("5. Return to Main Menu")            choice = input("\nChoice: ").strip()            match choice:                case "1":                    self._add_book()                case "2":                    self._remove_book()                case "3":                    format_book_list(self.books.get_all_books())                case "4":                    self._search_books()                case "5":                    break                case _:                    print("Invalid choice.")    def _add_book(self):        print("\n--- Add New Book ---")        try:            title = input("Title: ").strip()            author = input("Author: ").strip()            isbn = input("ISBN: ").strip()            year = int(input("Publication Year: "))            is_ref = input("Reference only? (y/n): ").lower() == "y"            book = Book(title, author, isbn, year, is_reference=is_ref)            self.books.add_book(book)            print(f"✓ '{title}' added successfully.")        except ValueError as e:            print(f"✗ Error: {e}")    def _remove_book(self):        isbn = input("Enter ISBN to remove: ").strip()        try:            book = self.books.remove_book(isbn)            print(f"✓ '{book.title}' removed.")        except (KeyError, ValueError) as e:            print(f"✗ Error: {e}")    def _search_books(self):        query = input("Search term (title/author): ").strip()        results = [b for b in self.books.get_all_books()                   if query.lower() in b.title.lower() or query.lower() in b.author.lower()]        format_book_list(results)    # ----------------------------------------------------------------------    # Member Management    # ----------------------------------------------------------------------    def _member_menu(self):        while True:            print("\n" + "-" * 30)            print("MEMBER MANAGEMENT")            print("-" * 30)            print("1. Register New Member")            print("2. View All Members")            print("3. View Member Details")            print("4. Pay Fine")            print("5. Return to Main Menu")            choice = input("\nChoice: ").strip()            match choice:                case "1":                    self._register_member()                case "2":                    format_member_list(self.members.get_all_members())                case "3":                    self._view_member_details()                case "4":                    self._pay_fine()                case "5":                    break                case _:                    print("Invalid choice.")    def _register_member(self):        print("\n--- Register New Member ---")        name = input("Full Name: ").strip()        member_id = input("Member ID: ").strip()        email = input("Email: ").strip()        phone = input("Phone: ").strip()        try:            member = Member(name, member_id, email, phone)            self.members.add_member(member)            print(f"✓ Member '{name}' registered.")        except ValueError as e:            print(f"✗ Error: {e}")    def _view_member_details(self):        member_id = input("Enter Member ID: ").strip()        member = self.members.find_by_id(member_id)        if not member:            print("Member not found.")            return        print("\n" + member.get_display_info())        active_loans = self.loans.get_active_loans_for_member(member_id)        if active_loans:            print("\n  Currently Borrowed:")            for loan in active_loans:                book = self.books.find_by_isbn(loan.book_isbn)                if book:                    status = "OVERDUE" if loan.is_overdue() else "On time"                    print(f"    - {book.title} (Due: {loan.due_date.strftime('%Y-%m-%d')}) [{status}]")    def _pay_fine(self):        member_id = input("Member ID: ").strip()        member = self.members.find_by_id(member_id)        if not member:            print("Member not found.")            return        if member.get_fines_owed() == 0.0:            print("This member has no fines to pay.")            return        print(f"Current fines: ${member.get_fines_owed():.2f}")        try:            amount = float(input("Payment amount: $"))            paid = member.pay_fine(amount)            print(f"✓ Payment of ${paid:.2f} accepted. Remaining: ${member.get_fines_owed():.2f}")        except ValueError:            print("Invalid amount.")    # ----------------------------------------------------------------------    # Loan Management    # ----------------------------------------------------------------------    def _loan_menu(self):        while True:            print("\n" + "-" * 30)            print("LOAN MANAGEMENT")            print("-" * 30)            print("1. Check Out Book")            print("2. Check In Book")            print("3. View Active Loans")            print("4. View Overdue Loans")            print("5. Return to Main Menu")            choice = input("\nChoice: ").strip()            match choice:                case "1":                    self._check_out_book()                case "2":                    self._check_in_book()                case "3":                    format_loan_list(self.loans.get_all_active_loans(), self.books, self.members)                case "4":                    self._view_overdue_loans()                case "5":                    break                case _:                    print("Invalid choice.")    def _check_out_book(self):        member_id = input("Member ID: ").strip()        isbn = input("Book ISBN: ").strip()        success, msg, _ = self.loan_service.check_out_book(member_id, isbn)        print(f"{'✓' if success else '✗'} {msg}")    def _check_in_book(self):        member_id = input("Member ID: ").strip()        isbn = input("Book ISBN: ").strip()        success, msg, fine = self.loan_service.check_in_book(isbn, member_id)        print(f"{'✓' if success else '✗'} {msg}")    def _view_overdue_loans(self):        overdue = self.loans.get_overdue_loans()        if not overdue:            print("\nNo overdue books.")            return        print("\n--- Overdue Loans ---")        for loan in overdue:            book = self.books.find_by_isbn(loan.book_isbn)            member = self.members.find_by_id(loan.member_id)            if book and member:                days = loan.get_days_overdue()                fine = self.fine_calculator.calculate_loan_fine(loan)                print(f"  {book.title} borrowed by {member.name}")                print(f"    Days overdue: {days} | Fine accrued: ${fine:.2f}")    # ----------------------------------------------------------------------    # Reports    # ----------------------------------------------------------------------    def _reports_menu(self):        while True:            print("\n" + "-" * 30)            print("REPORTS")            print("-" * 30)            print("1. Library Statistics")            print("2. Members with Fines")            print("3. Return to Main Menu")            choice = input("\nChoice: ").strip()            match choice:                case "1":                    self._show_statistics()                case "2":                    self._show_members_with_fines()                case "3":                    break                case _:                    print("Invalid choice.")    def _show_statistics(self):        print("\n--- Library Statistics ---")        print(f"Total Books: {self.books.count()}")        print(f"Available Books: {self.books.count_available()}")        print(f"Checked Out: {self.books.count() - self.books.count_available()}")        print(f"Total Members: {self.members.count()}")        print(f"Active Loans: {self.loans.count_active()}")        print(f"Overdue Loans: {len(self.loans.get_overdue_loans())}")    def _show_members_with_fines(self):        members = self.members.get_members_with_fines()        if not members:            print("\nNo members with outstanding fines.")            return        print("\n--- Members with Fines ---")        for m in members:            print(f"  {m.name} (ID: {m.member_id}): ${m.get_fines_owed():.2f}")    # ----------------------------------------------------------------------    # Helpers    # ----------------------------------------------------------------------    def _print_header(self, text):        print("\n" + "=" * 50)        print(text)        print("=" * 50)    def _confirm(self, message):        resp = input(f"{message} (y/n): ").strip().lower()        return resp in ["y", "yes"]